CREATE OR REPLACE FUNCTION fpb_pl_get_dep_must_loan ( as_reqno char ) RETURNS bigint AS $body$
DECLARE

ldc_dep_coll  sc_lon_m_req_coll.req_amount%type;
ldc_full_amt  sc_lon_m_req_coll.full_amount%type;

BEGIN
  select  sum( sc_lon_m_req_coll.req_amount ), sum( full_amount )
  into STRICT    ldc_dep_coll  , ldc_full_amt
  from    sc_lon_m_req_coll
  where   sc_lon_m_req_coll.loan_requestment_no = as_reqno
  and     sc_lon_m_req_coll.mustcoll_loan = '1';

  if coalesce(ldc_dep_coll::text, '') = '' then ldc_dep_coll := 0;end if;
  if coalesce(ldc_full_amt::text, '') = '' then ldc_full_amt := 0;end if;
  ldc_dep_coll := ldc_dep_coll - ldc_full_amt;
  if ldc_dep_coll < 0  then ldc_dep_coll := 0;end if;
  RETURN ldc_dep_coll;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
